engine = create_async_engine(
    settings.database_url,
    echo=False,
    connect_args={'check_same_thread': False}
)

@event.listens_for(engine.sync_engine, 'connect')
def set_sqlite_pragma(dbapi_conn, _):
    cursor = dbapi_conn.cursor()
    cursor.execute('PRAGMA foreign_keys=ON')
    cursor.execute('PRAGMA journal_mode=WAL')
    cursor.close()

AsyncSessionLocal = async_sessionmaker(
    engine, class_=AsyncSession, expire_on_commit=False
)

class Base(DeclarativeBase):
    pass

async def get_db():
    async with AsyncSessionLocal() as session:
        try:
            yield session
            await session.commit()
        except Exception:
            await session.rollback()
            raise

from datetime import datetime, timedelta, timezone
from collections import defaultdict
from time import time
from typing import Callable
import jwt
from passlib.context import CryptContext
from fastapi import Cookie, Depends, HTTPException, status
from sqlalchemy.ext.asyncio import AsyncSession
from app.core.config import settings
from app.core.database import get_db

pwd_context = CryptContext(schemes=['bcrypt'], deprecated='auto')
_pin_attempts: dict[str, list[float]] = defaultdict(list)

def hash_password(password: str) -> str:
    return pwd_context.hash(password)

def verify_password(plain: str, hashed: str) -> bool:
    return pwd_context.verify(plain, hashed)

def create_access_token(user_id: str, expires_days: int = 30) -> str:
    payload = {
        'sub': user_id,
        'exp': datetime.now(timezone.utc) + timedelta(days=expires_days)
    }
    return jwt.encode(payload, settings.secret_key, algorithm='HS256')

def decode_token(token: str) -> dict:
    return jwt.decode(token, settings.secret_key, algorithms=['HS256'])

def check_pin_rate_limit(user_id: str) -> None:
    now = time()
    attempts = [t for t in _pin_attempts[user_id] if now - t < 60]
    _pin_attempts[user_id] = attempts
    if len(attempts) >= 5:
        raise HTTPException(status_code=429, detail='Too many PIN attempts. Wait 60 seconds.')
    _pin_attempts[user_id].append(now)

async def get_current_user(
    access_token: str | None = Cookie(default=None),
    db: AsyncSession = Depends(get_db)
):
    from app.models.auth import User
    if not access_token:
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED)
    try:
        payload = decode_token(access_token)
        user_id: str = payload.get('sub')
    except jwt.PyJWTError:
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED)
    user = await db.get(User, user_id)
    if not user or user.is_deleted:
        raise HTTPException(status_code=status.HTTP_401_UNAUTHORIZED)
    return user

def require_role(*roles: str) -> Callable:
    async def dependency(current_user=Depends(get_current_user)):
        if current_user.role not in roles:
            raise HTTPException(status_code=status.HTTP_403_FORBIDDEN)
        return current_user
    return dependency

import os
import base64
from cryptography.hazmat.primitives.ciphers.aead import AESGCM
from cryptography.hazmat.primitives.kdf.hkdf import HKDF
from cryptography.hazmat.primitives import hashes
from app.core.config import settings

def _derive_key() -> bytes:
    return HKDF(
        algorithm=hashes.SHA256(),
        length=32,
        salt=None,
        info=b'familyhub-oauth-encryption'
    ).derive(settings.secret_key.encode())

def encrypt(plaintext: str) -> str:
    key = _derive_key()
    nonce = os.urandom(12)
    ct = AESGCM(key).encrypt(nonce, plaintext.encode(), None)
    return base64.urlsafe_b64encode(nonce + ct).decode()

def decrypt(ciphertext: str) -> str:
    key = _derive_key()
    data = base64.urlsafe_b64decode(ciphertext.encode())
    nonce, ct = data[:12], data[12:]
    return AESGCM(key).decrypt(nonce, ct, None).decode()

from typing import Callable
import asyncio

class EventBus:
    def __init__(self):
        self._listeners: list[Callable] = []

    def subscribe(self, callback: Callable) -> Callable:
        self._listeners.append(callback)
        def unsubscribe():
            self._listeners.remove(callback)
        return unsubscribe

    async def emit(self, event_type: str, payload: dict) -> None:
        message = {'type': event_type, 'data': payload}
        dead = []
        for listener in self._listeners:
            try:
                await listener(message)
            except Exception:
                dead.append(listener)
        for d in dead:
            self._listeners.remove(d)

event_bus = EventBus()

