from dateutil.rrule import rrulestr
from datetime import datetime, timezone

def next_occurrence(rrule_str: str, after: datetime) -> datetime | None:
    try:
        rule = rrulestr(rrule_str, dtstart=after)
        return rule.after(after)
    except Exception:
        return None

import { useEffect, useRef, useState, useCallback } from 'react'
import { WallClock } from './WallClock'
import { WallEventStrip } from './WallEventStrip'
import { WallChoreStatus } from './WallChoreStatus'
import { WallPhotoSlideshow } from './WallPhotoSlideshow'

const IDLE_MS = (parseInt(import.meta.env.VITE_WALL_IDLE_TIMEOUT_SECONDS ?? '300')) * 1000

export function WallLayout() {
  const [isIdle, setIsIdle] = useState(false)
  const timerRef = useRef<ReturnType<typeof setTimeout>>()

  const resetIdle = useCallback(() => {
    clearTimeout(timerRef.current)
    setIsIdle(false)
    timerRef.current = setTimeout(() => setIsIdle(true), IDLE_MS)
  }, [])

  useEffect(() => {
    document.addEventListener('touchstart', resetIdle, { passive: true })
    document.addEventListener('mousemove', resetIdle)
    resetIdle()
    return () => {
      document.removeEventListener('touchstart', resetIdle)
      document.removeEventListener('mousemove', resetIdle)
      clearTimeout(timerRef.current)
    }
  }, [resetIdle])

  if (isIdle) {
    return (
      <div className='fixed inset-0 bg-black' onClick={resetIdle}>
        <WallPhotoSlideshow fullscreen />
        <WallClock className='absolute bottom-4 right-6 text-white opacity-80' />
      </div>
    )
  }

  return (
    <div className='w-screen h-screen overflow-hidden grid grid-cols-2 grid-rows-[auto_1fr] gap-4 p-4 bg-gray-950 text-white'>
      <WallClock />
      <WallEventStrip />
      <div className='col-span-2'><WallChoreStatus /></div>
    </div>
  )
}

import { useState, useEffect } from 'react'

export function WallClock({ className = '' }: { className?: string }) {
  const [now, setNow] = useState(new Date())
  useEffect(() => {
    const id = setInterval(() => setNow(new Date()), 1000)
    return () => clearInterval(id)
  }, [])
  const time = now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', hour12: false })
  const date = now.toLocaleDateString([], { weekday: 'long', month: 'long', day: 'numeric' })
  return (
    <div className={`flex flex-col ${className}`}>
      <span className='text-7xl font-bold tracking-tight font-mono'>{time}</span>
      <span className='text-2xl text-gray-400 mt-1'>{date}</span>
    </div>
  )
}

import { useState, useEffect } from 'react'
import { useQuery } from '@tanstack/react-query'
import { apiClient } from '../api/client'

export function WallPhotoSlideshow({ fullscreen = false }: { fullscreen?: boolean }) {
  const [idx, setIdx] = useState(0)
  const [visible, setVisible] = useState(true)

  const { data: albums } = useQuery({
    queryKey: ['slideshow-albums'],
    queryFn: () => apiClient.get('/albums').then(r => r.data.filter((a: any) => a.slideshow_eligible))
  })

  // Flatten photos from all slideshow albums
  const photos = albums?.flatMap((a: any) => a.photos ?? []) ?? []

  useEffect(() => {
    if (photos.length === 0) return
    const duration = (albums?.[0]?.slideshow_duration_s ?? 10) * 1000
    const id = setInterval(() => {
      setVisible(false)
      setTimeout(() => {
        setIdx(i => (i + 1) % photos.length)
        setVisible(true)
      }, 600)
    }, duration)
    return () => clearInterval(id)
  }, [photos.length, albums])

  if (photos.length === 0) return <div className='bg-gray-900 flex items-center justify-center text-gray-600'>No photos</div>

  const photo = photos[idx]
  return (
    <div className={`relative ${fullscreen ? 'w-full h-full' : 'w-full h-full'} overflow-hidden bg-black`}>
      <img
        src={`/photos/thumbnails/${photo.id}_thumb.jpg`}
        className={`w-full h-full object-cover transition-opacity duration-500 ${visible ? 'opacity-100' : 'opacity-0'}`}
        alt={photo.caption ?? ''}
      />
      {photo.caption && (
        <div className='absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/60 p-4 text-white text-lg'>
          {photo.caption}
        </div>
      )}
    </div>
  )
}

from fastapi import APIRouter, WebSocket, WebSocketDisconnect
from app.core.events import event_bus
import logging

router = APIRouter()
logger = logging.getLogger(__name__)

class ConnectionManager:
    def __init__(self):
        self.active: list[WebSocket] = []

    async def connect(self, ws: WebSocket):
        await ws.accept()
        self.active.append(ws)
        logger.info('Wall WS connected. Total: %d', len(self.active))

    def disconnect(self, ws: WebSocket):
        if ws in self.active:
            self.active.remove(ws)

    async def broadcast(self, message: dict):
        dead = []
        for ws in self.active:
            try:
                await ws.send_json(message)
            except Exception:
                dead.append(ws)
        for ws in dead:
            self.active.remove(ws)

manager = ConnectionManager()

@router.websocket('/api/ws/wall')
async def wall_websocket(websocket: WebSocket):
    await manager.connect(websocket)
    unsubscribe = event_bus.subscribe(manager.broadcast)
    try:
        while True:
            await websocket.receive_text()
    except WebSocketDisconnect:
        manager.disconnect(websocket)
        unsubscribe()

import { useState, useEffect } from 'react'

export function OfflineBanner() {
  const [offline, setOffline] = useState(!navigator.onLine)
  useEffect(() => {
    const on = () => setOffline(false)
    const off = () => setOffline(true)
    window.addEventListener('online', on)
    window.addEventListener('offline', off)
    return () => { window.removeEventListener('online', on); window.removeEventListener('offline', off) }
  }, [])
  if (!offline) return null
  return (
    <div className='fixed top-0 left-0 right-0 z-50 bg-yellow-400 text-yellow-900 text-center py-2 text-sm font-medium'>
      You're offline — showing saved data
    </div>
  )
}

import { useState, useEffect } from 'react'

interface BeforeInstallPromptEvent extends Event {
  prompt: () => Promise<void>
  userChoice: Promise<{ outcome: 'accepted' | 'dismissed' }>
}

const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent)
const isStandalone = window.matchMedia('(display-mode: standalone)').matches

export function InstallPrompt() {
  const [deferredPrompt, setDeferredPrompt] = useState<BeforeInstallPromptEvent | null>(null)
  const [showIOSGuide, setShowIOSGuide] = useState(false)

  useEffect(() => {
    if (isIOS && !isStandalone && !localStorage.getItem('ios-install-shown')) {
      setTimeout(() => setShowIOSGuide(true), 5000)
    }
    const handler = (e: Event) => {
      e.preventDefault()
      setDeferredPrompt(e as BeforeInstallPromptEvent)
    }
    window.addEventListener('beforeinstallprompt', handler)
    return () => window.removeEventListener('beforeinstallprompt', handler)
  }, [])

  const handleInstall = async () => {
    if (!deferredPrompt) return
    await deferredPrompt.prompt()
    setDeferredPrompt(null)
  }

  if (showIOSGuide) return (
    <div className='fixed bottom-4 left-4 right-4 bg-white rounded-xl shadow-lg p-4 z-50'>
      <p className='font-medium text-gray-900 mb-1'>Install FamilyHub</p>
      <p className='text-sm text-gray-600'>Tap the Share button, then "Add to Home Screen"</p>
      <button className='mt-3 text-sm text-indigo-600' onClick={() => { setShowIOSGuide(false); localStorage.setItem('ios-install-shown','1') }}>Got it</button>
    </div>
  )

  if (deferredPrompt) return (
    <div className='fixed bottom-4 left-4 right-4 bg-indigo-600 text-white rounded-xl p-4 z-50 flex items-center justify-between'>
      <span className='text-sm font-medium'>Install FamilyHub for quick access</span>
      <button onClick={handleInstall} className='bg-white text-indigo-600 px-3 py-1 rounded-lg text-sm font-medium ml-4'>Install</button>
    </div>
  )

  return null
}
